import React from 'react';
import { CheckCircle2, XCircle, Share2, Download, Copy } from 'lucide-react';
import { useCurrency } from '../context/CurrencyContext';

export default function TransactionReceiptScreen({
  transaction,
  status = 'success',
  onDone,
  onShare,
  darkMode,
  onDownload
}) {
  const { formatAmount } = useCurrency();
  const isSuccess = status === 'success';

  return (
    <div className="h-full bg-gray-50 p-6 flex flex-col justify-center animate-in zoom-in-95 duration-300">
      <div className="bg-white rounded-[3rem] p-8 shadow-2xl relative overflow-hidden">

        {/* Top highlight bar */}
        <div
          className={`absolute top-0 left-0 w-full h-3 ${
            isSuccess ? 'bg-[#00875A]' : 'bg-red-500'
          }`}
        />

        {/* Status */}
        <div className="flex flex-col items-center mb-10 mt-4">
          <div
            className={`w-20 h-20 rounded-full flex items-center justify-center mb-6 shadow-inner ${
              isSuccess
                ? 'bg-emerald-50 text-[#00875A]'
                : 'bg-red-50 text-red-500'
            }`}
          >
            {isSuccess ? (
              <CheckCircle2 size={48} strokeWidth={2.5} />
            ) : (
              <XCircle size={48} strokeWidth={2.5} />
            )}
          </div>

          <h2 className="text-xl font-black text-gray-900">
            {isSuccess ? 'Payment Successful' : 'Transaction Failed'}
          </h2>

          <p className="text-4xl font-black mt-3 text-gray-900 tracking-tight">
            {formatAmount(transaction.amount)}
          </p>
        </div>

        {/* Transaction Details */}
        <div className="space-y-5 pt-6 border-t border-dashed border-gray-200">
          {[
            { label: 'Recipient / Source', value: transaction.title || 'Nest Balance' },
            { label: 'Transaction ID', value: transaction.reference, icon: Copy },
            { label: 'Date', value: new Date(transaction.date).toLocaleString() },
            {
              label: 'Payment Status',
              value: isSuccess ? 'Completed' : 'Failed',
              highlight: isSuccess ? 'text-[#00875A]' : 'text-red-500',
            },
          ].map((row, idx) => (
            <div key={idx} className="flex justify-between items-center text-sm">
              <span className="text-gray-400 font-bold uppercase tracking-wider text-[10px]">
                {row.label}
              </span>
              <div className="flex items-center gap-2">
                <span className={`font-black ${row.highlight || 'text-gray-900'}`}>
                  {row.value}
                </span>
                {row.icon && <row.icon size={12} className="text-gray-300 cursor-pointer" />}
              </div>
            </div>
          ))}
        </div>

        {/* Actions */}
        <div className="flex gap-4 mt-12">
          <button
            onClick={() => onShare?.(transaction)}
            className="flex-1 flex flex-col items-center gap-2 group"
          >
            <div className="w-12 h-12 bg-gray-50 rounded-2xl flex items-center justify-center text-gray-600 group-active:scale-95 transition-transform">
              <Share2 size={20} />
            </div>
            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
              Share
            </span>
          </button>

          <button
            disabled={!isSuccess}
            onClick={() => onDownload?.(transaction)}
            className={`flex-1 flex flex-col items-center gap-2 group ${
              !isSuccess && 'opacity-40 pointer-events-none'
            }`}
          >
            <div className="w-12 h-12 bg-gray-50 rounded-2xl flex items-center justify-center text-gray-600 group-active:scale-95 transition-transform">
              <Download size={20} />
            </div>
            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
              Save PDF
            </span>
          </button>
        </div>
      </div>

      {/* Close */}
      <button
        onClick={onDone}
        className="mt-10 w-full py-4 rounded-2xl font-black text-white bg-gray-900 shadow-xl active:scale-95 transition-all"
      >
        Close Receipt
      </button>
    </div>
  );
}
